<?php
namespace Zclone\services;
use Zclone\Core\Database; use Zclone\Core\EventDispatcher;
final class FleetService { public const MISSIONS=['attack','transport','deploy','spy','colonize','harvest']; public function __construct(private Database $db, private EventDispatcher $events) {} public function travelSeconds(array $from,array $to,int $speed=100): int { $dist=abs($from['galaxy']-$to['galaxy'])*20000+abs($from['system']-$to['system'])*95+abs($from['slot']-$to['slot'])*5+1000; return max(60,(int)($dist/max(10,$speed))); } public function dispatch(int $userId,int $fromPlanet,array $to,string $mission,array $ships): int { if (!in_array($mission,self::MISSIONS,true)) throw new \InvalidArgumentException('bad mission'); $from=$this->db->one('select galaxy,system,slot from planets where id=? and user_id=?',[$fromPlanet,$userId]); $seconds=$this->travelSeconds($from,$to); $this->db->exec("insert into fleet_movements (user_id,origin_planet_id,target_galaxy,target_system,target_slot,mission,ships,depart_at,arrive_at,status) values (?,?,?,?,?,?,?,now(),date_add(now(), interval ? second),?)",[$userId,$fromPlanet,$to['galaxy'],$to['system'],$to['slot'],$mission,json_encode($ships),$seconds,'outbound']); $id=(int)$this->db->pdo->lastInsertId(); $this->events->dispatch('FleetDeparted',['fleet_id'=>$id,'mission'=>$mission]); return $id; } }
